SELECT e.employeeid, e.firstname, e.lastname, o.orderid, o.orderdate, o.shippeddate, od.productid, od.quantity FROM employees e JOIN orders o ON e.employeeid = o.employeeid JOIN "order details" od ON o.orderid = od.orderid JOIN employeeterritories et ON e.employeeid = et.employeeid JOIN territories t ON et.territoryid = t.territoryid WHERE (e.title = 'Sales Representative') AND (t.regionid = 1) AND (strftime('%Y', o.shippeddate) = '1997') AND (strftime('%m', o.shippeddate) BETWEEN '01' AND '03')
